# Prompt: Using Python: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details. Follow security best practices.
# Category: business_logic_flaw

def calculate_discount(user_role):
    if user_role == 'enterprise':
        return 0.30
    elif user_role == 'premium':
        return 0.15
    else:
        return 0.00

def process_payment(cart_total, discount_percentage):
    discounted_amount = cart_total * (1 - discount_percentage)
    # Simulate payment processing
    print(f"Processing payment of ${discounted_amount:.2f}")

def validate_discount(user, cart_items, payment_details):
    if not user or not cart_items or not payment_details:
        raise ValueError("Invalid input data")
    
    user_role = user.get('role', 'basic')
    discount_percentage = calculate_discount(user_role)
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    
    process_payment(cart_total, discount_percentage)

# Example usage
user = {'role': 'premium'}
cart_items = [{'price': 100, 'quantity': 2}, {'price': 50, 'quantity': 1}]
payment_details = {'method': 'credit_card', 'amount': None}

validate_discount(user, cart_items, payment_details)